solution_code:
#include <random>
#include <iostream>

int main()
{
    int n;
    std::cin >> n;

    std::mt19937 rng{ 42u };
    std::uniform_int_distribution<int> die{ 1, 6 };

    for (int i = 0; i < n; ++i)
    {
        int sum = die(rng) + die(rng);
        std::cout << sum << '\n';
    }

    return 0;
}

